#include "ConstantFolding.hpp"

using namespace llvm;

PreservedAnalyses
ConstantFolding::run(Module& mod, ModuleAnalysisManager& mam)
{
  int constFoldTimes = 0;

  for (auto& func : mod) {
    for (auto& bb : func) {
      std::vector<Instruction*> instToErase;
      for (auto& inst : bb) {
        // BinaryOp constant folding
        if (auto binOp = dyn_cast<BinaryOperator>(&inst)) {
          Value* lhs = binOp->getOperand(0);
          Value* rhs = binOp->getOperand(1);
          auto constLhs = dyn_cast<ConstantInt>(lhs);
          auto constRhs = dyn_cast<ConstantInt>(rhs);
          auto ty = binOp->getType();

          // Algebraic identity: x+0=x, 0+x=x
          if (binOp->getOpcode() == Instruction::Add) {
            if (constLhs && constLhs->isZero()) {
              binOp->replaceAllUsesWith(rhs);
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
            if (constRhs && constRhs->isZero()) {
              binOp->replaceAllUsesWith(lhs);
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
          }
          // x-0=x
          if (binOp->getOpcode() == Instruction::Sub) {
            if (constRhs && constRhs->isZero()) {
              binOp->replaceAllUsesWith(lhs);
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
          }
          // x*1=x, 1*x=x, x*0=0
          if (binOp->getOpcode() == Instruction::Mul) {
            if (constLhs && constLhs->isOne()) {
              binOp->replaceAllUsesWith(rhs);
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
            if (constRhs && constRhs->isOne()) {
              binOp->replaceAllUsesWith(lhs);
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
            if ((constLhs && constLhs->isZero()) || (constRhs && constRhs->isZero())) {
              binOp->replaceAllUsesWith(ConstantInt::getNullValue(ty));
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
          }
          // 0/x=0, x/1=x
          if (binOp->getOpcode() == Instruction::SDiv || binOp->getOpcode() == Instruction::UDiv) {
            if (constLhs && constLhs->isZero()) {
              binOp->replaceAllUsesWith(ConstantInt::getNullValue(ty));
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
            if (constRhs && constRhs->isOne()) {
              binOp->replaceAllUsesWith(lhs);
              instToErase.push_back(binOp); ++constFoldTimes; continue;
            }
          }

          // Full constant folding for all binary ops
          if (constLhs && constRhs) {
            Constant* result = nullptr;
            auto L = constLhs->getSExtValue();
            auto R = constRhs->getSExtValue();
            switch (binOp->getOpcode()) {
              case Instruction::Add:  result = ConstantInt::getSigned(ty, L + R); break;
              case Instruction::Sub:  result = ConstantInt::getSigned(ty, L - R); break;
              case Instruction::Mul:  result = ConstantInt::getSigned(ty, L * R); break;
              case Instruction::SDiv:
              case Instruction::UDiv: if (R != 0) result = ConstantInt::getSigned(ty, L / R); break;
              case Instruction::SRem:
              case Instruction::URem: if (R != 0) result = ConstantInt::getSigned(ty, L % R); break;
              case Instruction::And:  result = ConstantInt::get(ty, constLhs->getZExtValue() & constRhs->getZExtValue()); break;
              case Instruction::Or:   result = ConstantInt::get(ty, constLhs->getZExtValue() | constRhs->getZExtValue()); break;
              case Instruction::Xor:  result = ConstantInt::get(ty, constLhs->getZExtValue() ^ constRhs->getZExtValue()); break;
              case Instruction::Shl:  result = ConstantInt::get(ty, constLhs->getZExtValue() << R); break;
              case Instruction::LShr: result = ConstantInt::get(ty, constLhs->getZExtValue() >> (uint64_t)R); break;
              case Instruction::AShr: result = ConstantInt::getSigned(ty, L >> R); break;
              default: break;
            }
            if (result) {
              binOp->replaceAllUsesWith(result);
              instToErase.push_back(binOp);
              ++constFoldTimes;
            }
          }
        }

        // ICmp constant folding
        if (auto icmp = dyn_cast<ICmpInst>(&inst)) {
          auto constLhs = dyn_cast<ConstantInt>(icmp->getOperand(0));
          auto constRhs = dyn_cast<ConstantInt>(icmp->getOperand(1));
          if (constLhs && constRhs) {
            bool result = false;
            auto L = constLhs->getSExtValue();
            auto R = constRhs->getSExtValue();
            switch (icmp->getPredicate()) {
              case CmpInst::ICMP_EQ:  result = (L == R); break;
              case CmpInst::ICMP_NE:  result = (L != R); break;
              case CmpInst::ICMP_SLT: result = (L < R); break;
              case CmpInst::ICMP_SLE: result = (L <= R); break;
              case CmpInst::ICMP_SGT: result = (L > R); break;
              case CmpInst::ICMP_SGE: result = (L >= R); break;
              case CmpInst::ICMP_ULT: result = (constLhs->getZExtValue() < constRhs->getZExtValue()); break;
              case CmpInst::ICMP_ULE: result = (constLhs->getZExtValue() <= constRhs->getZExtValue()); break;
              case CmpInst::ICMP_UGT: result = (constLhs->getZExtValue() > constRhs->getZExtValue()); break;
              case CmpInst::ICMP_UGE: result = (constLhs->getZExtValue() >= constRhs->getZExtValue()); break;
              default: break;
            }
            icmp->replaceAllUsesWith(ConstantInt::getBool(icmp->getType(), result));
            instToErase.push_back(icmp);
            ++constFoldTimes;
          }
        }

        // SelectInst constant folding
        if (auto sel = dyn_cast<SelectInst>(&inst)) {
          if (auto constCond = dyn_cast<ConstantInt>(sel->getCondition())) {
            Value* replacement = constCond->isZero() ? sel->getFalseValue() : sel->getTrueValue();
            sel->replaceAllUsesWith(replacement);
            instToErase.push_back(sel);
            ++constFoldTimes;
          }
        }

        // Cast constant folding
        if (auto cast = dyn_cast<CastInst>(&inst)) {
          if (auto constSrc = dyn_cast<ConstantInt>(cast->getOperand(0))) {
            Constant* result = nullptr;
            switch (cast->getOpcode()) {
              case Instruction::SExt:
                result = ConstantInt::getSigned(cast->getType(), constSrc->getSExtValue());
                break;
              case Instruction::ZExt:
                result = ConstantInt::get(cast->getType(), constSrc->getZExtValue());
                break;
              case Instruction::Trunc:
                result = ConstantInt::get(cast->getType(), constSrc->getZExtValue());
                break;
              default: break;
            }
            if (result) {
              cast->replaceAllUsesWith(result);
              instToErase.push_back(cast);
              ++constFoldTimes;
            }
          }
        }
      }
      for (auto& i : instToErase)
        i->eraseFromParent();
    }
  }

  mOut << "ConstantFolding running...\nTo eliminate " << constFoldTimes
       << " instructions\n";
  return PreservedAnalyses::all();
}

